import{d,o as r,c as s,e as l,j as a,t as h,_ as u,C as p,a as f,E as i,al as n}from"./chunks/framework.BJsoK6mY.js";const m="/assets/vanilla.qwVz-msJ.webp",g="/assets/1.CXRLLEnC.webp",v="/assets/2.BQg5L6BI.webp",k="/assets/3.DG-hV-IH.webp",b=["href"],y=["src","alt"],w={class:"yt-card__content"},E={class:"yt-card__title"},C={key:0,class:"yt-card__description"},_=d({__name:"YouTubeCard",props:{title:{},href:{},thumbnail:{},description:{}},setup(t){return(c,e)=>(r(),s("a",{class:"yt-card",href:t.href,target:"_blank",rel:"noreferrer"},[t.thumbnail?(r(),s("img",{key:0,class:"yt-card__thumb",src:t.thumbnail,alt:t.title},null,8,y)):l("",!0),a("div",w,[e[0]||(e[0]=a("div",{class:"yt-card__label"},"Video",-1)),a("div",E,h(t.title),1),t.description?(r(),s("div",C,h(t.description),1)):l("",!0),e[1]||(e[1]=a("div",{class:"yt-card__cta"},"Watch on YouTube →",-1))])],8,b))}}),F=u(_,[["__scopeId","data-v-cf88381c"]]),x=JSON.parse('{"title":"How to create a Minecraft Server (2026)","titleTemplate":"Vite & Vue powered static site generator","description":"","frontmatter":{"title":"How to create a Minecraft Server (2026)","titleTemplate":"Vite & Vue powered static site generator","layout":"doc","outline":null,"level":[2,3],"label":"Contents"},"headers":[],"relativePath":"videos/minecraft-server-2026.md","filePath":"en/videos/minecraft-server-2026.md","lastUpdated":1776350547000}'),q={name:"videos/minecraft-server-2026.md"},T=d({...q,setup(t){return(c,e)=>{const o=p("VpFolderTree");return r(),s("div",null,[e[0]||(e[0]=a("h1",{id:"minecraft-server-tutorial-2026",tabindex:"-1"},[f("Minecraft Server Tutorial (2026) "),a("a",{class:"header-anchor",href:"#minecraft-server-tutorial-2026","aria-label":'Permalink to "Minecraft Server Tutorial (2026)"'},"​")],-1)),i(F,{title:"How to create a Minecraft Server (2026)",href:"https://www.youtube.com/watch?v=-h_D9IEJOeM",thumbnail:"https://img.youtube.com/vi/-h_D9IEJOeM/maxresdefault.jpg",description:"A walkthrough of the feature shown in this guide."}),e[1]||(e[1]=n('<h2 id="general-information" tabindex="-1">General Information <a class="header-anchor" href="#general-information" aria-label="Permalink to &quot;General Information&quot;">​</a></h2><h3 id="terminology" tabindex="-1">Terminology <a class="header-anchor" href="#terminology" aria-label="Permalink to &quot;Terminology&quot;">​</a></h3><p>Before we continue with this tutorial lets talk about some basic terminology I will use going forward so you dont get confused 😃</p><table tabindex="0"><thead><tr><th>Term</th><th>Meaning</th></tr></thead><tbody><tr><td>Client</td><td>The Client is effectively the game that you start on your local computer. Lets compare it to a plane for now.</td></tr><tr><td>Server</td><td>An instance of minecraft running in your terminal without a graphical preview, this is what your client connects to. You can imagine this similar to a big airport.</td></tr><tr><td>Terminal</td><td>The Terminal, Command Prompt or &quot;CMD&quot; is a Windows Application that lets you run &quot;commands&quot;. It lets you interact with apps that dont have a graphical user interface (GUI)</td></tr><tr><td>Vanilla</td><td>This word in general describes the unmodified version of a game, directly as it came from the game developer. This definition is not unique to Minecraft.</td></tr><tr><td>Server Software</td><td>Once we want plugins and mods to work on our server, the vanilla <strong>server</strong> software will not be sufficient anymore. Therefore developers created their own &quot;Server Software&quot;, which includes all the features from the vanilla server aswell new ones like plugin support.</td></tr><tr><td>Mod Loaders</td><td>Similar to Server Software, Mod Loaders describe modified Version of the vanilla <strong>client</strong> that include further features like mod support and performance improvements.</td></tr></tbody></table><h3 id="folder" tabindex="-1">Creating a server folder <a class="header-anchor" href="#folder" aria-label="Permalink to &quot;Creating a server folder {#folder}&quot;">​</a></h3><p>Having a good organisation early on is pretty important when you start creating multiple servers for different purposes:</p><ul><li>Start by creating a folder called &quot;Minecraft Servers&quot; or something similar somewhere where you will remember its location. I would recommend either putting it at the root (most top level folder) on an external harddrive, in documents or somewhere in your user folder.</li><li>Inside that folder we will put all folders for our different minecraft servers. Start by creating a new folder inside that one and calling it &quot;First Server&quot; or something similar. The important part is that you remember which server is inside that folder without having to boot it up.</li></ul>',7)),i(o,{data:[{name:"[LOCATION OF YOUR CHOOSING]",isFolder:!0,children:[{name:"Minecraft Server",isFolder:!0,children:[{name:"First Minecraft Server",isFolder:!0,children:[{name:"server.jar",isFolder:!1},{name:"start.bat",isFolder:!1}],description:"Give this a good name that you will remember"},{name:"Second Minecraft Server",isFolder:!0,children:[{name:"...",isFolder:!1},{name:"...",isFolder:!1}]},{name:"...",isFolder:!0,children:[{name:"...",isFolder:!1}]}],description:"This folder will contain all your servers."}]}],"default-open":!0,"show-toolbar":!1,"show-badges":!0,interactive:!0}),e[2]||(e[2]=n(`<h3 id="java" tabindex="-1">Choosing the correct Java Version <a class="header-anchor" href="#java" aria-label="Permalink to &quot;Choosing the correct Java Version {#java}&quot;">​</a></h3><p>Minecraft is a pretty old game at this point and to keep the code safe and up to modern standards Mojang updated they Java version of the game every few updates. When we want to run a minecraft server we need to have the java version installed on our computer that our server was originally developed with.</p><table tabindex="0"><thead><tr><th>Minecraft Version</th><th style="text-align:right;">Java</th><th>Download</th></tr></thead><tbody><tr><td>1.16.5 and older</td><td style="text-align:right;">Java 8</td><td><a href="https://adoptium.net/de/temurin/releases?version=8" target="_blank" rel="noreferrer">Adoptium</a></td></tr><tr><td>1.17</td><td style="text-align:right;">Java 16</td><td><a href="https://adoptium.net/de/temurin/releases?version=16" target="_blank" rel="noreferrer">Adoptium</a>*</td></tr><tr><td>1.18 - 1.20.4</td><td style="text-align:right;">Java 17</td><td><a href="https://adoptium.net/de/temurin/releases?version=17" target="_blank" rel="noreferrer">Adoptium</a></td></tr><tr><td>1.20.5</td><td style="text-align:right;">Java 21</td><td><a href="https://adoptium.net/de/temurin/releases?version=21" target="_blank" rel="noreferrer">Adoptium</a></td></tr><tr><td>26.1 and newer</td><td style="text-align:right;">Java 25</td><td><a href="https://adoptium.net/de/temurin/releases?version=25" target="_blank" rel="noreferrer">Adoptium</a></td></tr></tbody></table><p>*only JDK available</p><p>When you have decided on which Minecraft Version your server will run, click the download link next to the corresponding Java version. This will redirect you to download page for Eclipse Temurin. When going through the installer make sure to select &quot;install feature on disk&quot; when asked if you want to change the JAVA_HOME variable.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Temurin is a free, open-source distribution of the Java Development Kit (JDK) built from OpenJDK and maintained by the Eclipse Adoptium project.</p></div><h3 id="batch" tabindex="-1">Creating a batch (.bat) file to start the Server <a class="header-anchor" href="#batch" aria-label="Permalink to &quot;Creating a batch (.bat) file to start the Server {#batch}&quot;">​</a></h3><p>In order for the minecraft server to run we need to create a batch file.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>You can think of the batch file as a &quot;shortcut&quot; or &quot;preset&quot; that tells the server file how to run the server e.g. how much RAM it should be able to use etc.</p></div><ol><li><strong>Step: Enabling File Extensions</strong><ul><li>Make sure to have &quot;show file extension&quot; checked in the Explorer under: <ul><li>View &gt; Show &gt; File Extension</li></ul></li></ul></li><li><strong>Step: Creating the file</strong><ul><li>Right click inside the folder of your server:</li><li>Select: New &gt; New text document</li></ul></li><li><strong>Step: Renaming the file correctly</strong><ul><li>Rename the file to &quot;start.bat&quot;. Make sure that the file no longer has the .txt ending.</li><li>The only important part is that the file ends with &quot;.bat&quot; the actual name does not matter, I just think that &quot;start&quot; makes everything a bit more clear 😃</li></ul></li><li><strong>Confirm the renaming and check the file type</strong><ul><li>Click &quot;yes&quot; when windows asks you if you want to change the file type.</li><li>After that double check while in &quot;detail&quot; view mode that in the &quot;File type&quot; row it says &quot;Windows Batch file&quot;</li></ul></li><li><strong>Start editing the file</strong><ul><li>Right click the file and then click &quot;Edit in Notepad&quot; or &quot;Edit&quot; depending on which Version of Windows you are on</li></ul></li></ol><h4 id="lets-start-the-editing-🎉" tabindex="-1">Lets start the editing! 🎉 <a class="header-anchor" href="#lets-start-the-editing-🎉" aria-label="Permalink to &quot;Lets start the editing! 🎉&quot;">​</a></h4><p>This is the most basic form of a batch file: It gets executed from top to bottom.</p><div class="language-bat vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bat</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">java -Xms4G -Xmx4G -jar server.jar nogui</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pause</span></span></code></pre></div><p>Here are the important variables in this code:</p><table tabindex="0"><thead><tr><th>code</th><th>function</th></tr></thead><tbody><tr><td>java</td><td>calls java</td></tr><tr><td>-Xms[...]</td><td>Set the <strong>minimum allocated</strong> RAM for the Server. This means that this server will always be reserved for the server and cannot be used by other programs. If not set, the unused RAM from the maximum RAM variable will be used by other programs until the server needs it.</td></tr><tr><td>-Xmx[...]</td><td>Sets the <strong>maximum allowed</strong> RAM for the Server. The server will never use more than this, so set this according to your needs like player count, mod count etc.</td></tr><tr><td>-jar</td><td>Tells Java to run the program from inside the .jar file</td></tr><tr><td>server.jar</td><td>This is the <strong>exact</strong> file name of your server file. Double check that this matches!</td></tr><tr><td>nogui</td><td>Mojang also has their own little chat window that appears when only running the server from the server file without a batch file. But since we already have the chat inside our terminal we dont need this little custom window. We disable it with the flag &quot;nogui&quot;</td></tr></tbody></table><h4 id="opt-batch" tabindex="-1">Optimized Batch File <a class="header-anchor" href="#opt-batch" aria-label="Permalink to &quot;Optimized Batch File {#opt-batch}&quot;">​</a></h4><p>There are custom flags you can add in this code which tell the server more specifically how to handle memory. The specific tweaks below are based on extensive research by Aikar, one of the developers behind PaperMC, who tried to find the most ideal flags to optimize server performance. <a href="https://aikar.co/2018/07/02/tuning-the-jvm-g1gc-garbage-collector-flags-for-minecraft/" target="_blank" rel="noreferrer">Aikar&#39;s Flag Guide</a> <a href="https://github.com/aikar" target="_blank" rel="noreferrer">Github</a></p><div class="language-bat vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bat</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">java -Xms10G -Xmx10G </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">^</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-XX:+UseG1GC -XX:+ParallelRefProcEnabled -XX:MaxGCPauseMillis=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">200</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ^</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-XX:+UnlockExperimentalVMOptions -XX:+DisableExplicitGC </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">^</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-XX:+AlwaysPreTouch -XX:G1NewSizePercent=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -XX:G1MaxNewSizePercent=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">40</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ^</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-XX:G1HeapRegionSize=8M -XX:G1ReservePercent=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -XX:G1HeapWastePercent=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ^</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-XX:G1MixedGCCountTarget=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -XX:InitiatingHeapOccupancyPercent=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">15</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ^</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-XX:G1MixedGCLiveThresholdPercent=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">90</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -XX:G1RSetUpdatingPauseTimePercent=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ^</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-XX:SurvivorRatio=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -XX:+PerfDisableSharedMem -XX:MaxTenuringThreshold=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ^</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-Dusing.aikars.flags=https://mcflags.emc.gs -Daikars.new.flags=true </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">^</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-jar server.jar nogui</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pause</span></span></code></pre></div><p>In the end make sure the .bat file is placed in your folder like this</p>`,19)),i(o,{data:[{name:"Minecraft Server",isFolder:!0,children:[{name:"start.bat",isFolder:!1},{name:"serverfile (e.g. server.jar)",isFolder:!1},{name:"...",isFolder:!1}],description:"This the "}],"default-open":!0,"show-toolbar":!1,"show-badges":!0,interactive:!0}),e[3]||(e[3]=n('<div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Please double check that in the end of the batch file the &quot;server.jar&quot; part is matching the name of your server file.</p></div><h2 id="vanilla" tabindex="-1">Vanilla Server <a class="header-anchor" href="#vanilla" aria-label="Permalink to &quot;Vanilla Server {#vanilla}&quot;">​</a></h2><p><img src="'+m+'" alt="Vanilla Server Banner"></p><hr><p>This section is meant to explain how to create a basic minecraft vanilla server. This means we will run an unmodified game server which does not support plugins or mods. If you want to create an SMP server for your friends I would recommend taking a look at the <a href="#paper">Paper Section</a> instead.</p><p>Before continuing make sure to create a folder for your server as explained in the <a href="#folder">folder creation</a> section and create a <a href="#batch">valid batch file</a></p><hr><h3 id="vanilla-server" tabindex="-1">Download the Server file <a class="header-anchor" href="#vanilla-server" aria-label="Permalink to &quot;Download the Server file{#vanilla-server}&quot;">​</a></h3><p>In order to download the server file for a vanilla server you need to open your Minecraft Launcher. Make sure you have &quot;Java Edition&quot; selected and then click on the &quot;Installations&quot; tab. The next step is to click the &quot;New Installation&quot; button.</p><div style="display:flex;flex-direction:row;gap:16px;align-items:flex-start;"><img src="'+g+'" style="width:50%;" alt="Select Java Edition on the right and then click on Installations"><img src="'+v+'" style="width:50%;" alt="Click the New Installation button"></div><br><div style="display:flex;flex-direction:row;gap:16px;align-items:flex-start;"><div style="width:70%;"> Once you click the &quot;New Installation&quot; button, select the minecraft version you want your server running on.<br><br> After that click the little &quot;Server&quot; text. This will download the official vanilla server for that version from official Mojang Servers. </div><img src="'+k+'" style="width:30%;" alt="Select your version from the dropdown and the click the server text"></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>If not done already, check which Java Version you need for that Minecraft Version with the <a href="#java">table</a> above. Make sure that when you open a terminal and enter the command <code>java -version</code> that it reports this back to you for confirmation.</p></div><hr><h3 id="move-the-server-jar-file-to-your-servers-folder" tabindex="-1">Move the server.jar file to your servers&#39; folder <a class="header-anchor" href="#move-the-server-jar-file-to-your-servers-folder" aria-label="Permalink to &quot;Move the server.jar file to your servers&#39; folder&quot;">​</a></h3><p>If you followed the folder creation, batch file creation and the upper server.jar instructions correctly, your folder should now look like this:</p>',16)),i(o,{data:[{name:"Vanilla Server",isFolder:!0,children:[{name:"start.bat",isFolder:!1},{name:"server.jar",isFolder:!1}],description:"Or however you want to call your server"}],"default-open":!0,"show-toolbar":!1,"show-badges":!0,interactive:!0})])}}});export{x as __pageData,T as default};
